import { query } from '~/lib/db';
import { ok, err, Result } from '~/lib/result';
import { Team, TeamError } from '../types';

/**
 * Renames an existing team.
 * @param teamId The ID of the team to rename.
 * @param newName The new name for the team.
 * @returns A Result containing the updated Team object on success, or a TeamError on failure.
 */
export async function renameTeam(teamId: string, newName: string): Promise<Result<Team, TeamError>> {
  if (!teamId || typeof teamId !== 'string' || teamId.trim() === '') {
    return err({ type: 'InvalidInput', message: 'Team ID is required and must be a non-empty string.' });
  }
  if (!newName || typeof newName !== 'string' || newName.trim() === '') {
    return err({ type: 'InvalidInput', message: 'New team name is required and cannot be empty.' });
  }

  try {
    // Check if the team exists
    const existingTeamResult = await query<Team>('SELECT id, name, created_at, updated_at FROM teams WHERE id = $1', [teamId]);
    if (existingTeamResult.rows.length === 0) {
      return err({ type: 'NotFound', message: `Team with ID '${teamId}' not found.` });
    }

    // Check for duplicate name (case-insensitive, excluding the current team)
    const duplicateNameResult = await query<Team>('SELECT id FROM teams WHERE LOWER(name) = LOWER($1) AND id != $2', [newName.trim(), teamId]);
    if (duplicateNameResult.rows.length > 0) {
      return err({ type: 'InvalidInput', message: `Team name '${newName.trim()}' already exists.` });
    }

    // Update the team name
    const updateResult = await query<Team>(
      'UPDATE teams SET name = $1, updated_at = NOW() WHERE id = $2 RETURNING id, name, created_at, updated_at',
      [newName.trim(), teamId]
    );

    if (updateResult.rows.length === 0) {
      // This case should ideally not happen if the team was found above,
      // but it's a good safeguard for concurrent updates or other unexpected issues.
      return err({ type: 'NotFound', message: `Failed to update team with ID '${teamId}'. It might have been deleted.` });
    }

    return ok(updateResult.rows[0]);
  } catch (error: any) {
    console.error(`Database error renaming team '${teamId}':`, error);
    return err({ type: 'DatabaseError', message: `Failed to rename team due to a database error: ${error.message}` });
  }
}
